code.C++:
#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;
    int numbers[n];
    for (int i = 0; i < n; ++i) {
        cin >> numbers[i];
    }

    for (int i = 0; i < n; i++) {
        if (numbers[i] == 8) {
           cout << i;            
           break;
        }
    }
    return 0;
}

